  methods: {
    count_in_array(array, element) {
      return array.filter((n) => n == element).length;
    },
    get_splited_list_from_sentence(text) {
      let raw_list = text.split(/(`(?:.*?)`)/);
      return raw_list;
    },
    get_info_dict_from_splited_list(list) {
      let new_list = [];
      list.forEach((text, index) => {
        let obj = {};
        obj.index = index;
        obj.right = false;
        if (text.includes("`")) {
          obj.raw = false;
          obj.text = text.replace(/`/g, "");
        } else {
          obj.raw = true;
          obj.text = text;
        }
        new_list.push(obj);
      });
      return new_list;
    },
    get_current_list(text) {
      let list = this.get_info_dict_from_splited_list(
        this.get_splited_list_from_sentence(text)
      );
      //console.log(list)
      return list;
    },
    update_current_list() {
      this.current_list = this.get_current_list(
        this.question_list[this.current_index]
      );
    },
    next_question() {
      //console.log("right");
      this.blank = {};
      if (this.$store.state.had_asked_for_help == true) {
        this.$store.commit("set_had_asked_for_help", false);
      } else {
        this.current_index = this.current_index + 1;
        if (this.current_index > this.question_list.length - 1) {
          this.current_index = 0;
        }
        this.update_current_list();
        this.$store.commit("set_blank_filling_progress", this.current_index);
      }
    },
    input_on_change(index, answer, right_answer) {
      answer = answer
        .replace(/[^%Ω/.\u4e00-\u9fa5_a-zA-Z0-9]/g, "")
        .toLowerCase();
      right_answer = right_answer
        .replace(/[^%Ω/.\u4e00-\u9fa5_a-zA-Z0-9]/g, "")
        .toLowerCase();

      if (answer.trim() == right_answer.trim()) {
        this.current_list[index].right = true;
      } else {
        this.current_list[index].right = false;
      }

      let target_list = this.current_list.filter((item) => {
        return item.raw == false;
      });
      let not_ok_list = target_list.filter((item) => {
        return item.right == false;
      });

      if (not_ok_list.length == 0) {
        this.next_question();
      } else {
        //console.log("wrong");
      }
    },
  },
};
