import Vue from 'vue'
import Vuex from 'vuex'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    blank_filling_progress: 0,

    single_choice_progress: 0,
    true_or_false_progress: 0,
    short_answer_progress: 0,
    sort_answer_progress: 0,

    show_answer: false,
    had_asked_for_help: false,
  },
  mutations: {
    set_blank_filling_progress(state, index) {
      state.blank_filling_progress = index
    },
    set_short_answer_progress(state, index) {
      state.short_answer_progress = index
    },
    set_single_choice_progress(state, index) {
      state.single_choice_progress = index
    },
    set_sort_answer_progress(state, index) {
      state.sort_answer_progress = index
    },

    set_had_asked_for_help(state, status) {
      state.had_asked_for_help = status
    }
  },
  actions: {
    async initialization(store) {
      if (localStorage.getItem('store')) {
        this.replaceState(
          Object.assign(store.state, JSON.parse(localStorage.getItem('store')))
        );
      }
    }
  },
  modules: {
  }
})
